#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int p1[2], p2[2];
    pipe(p1);                              // ★ pipe1 : p1[0]=lecture p1[1]=écriture
    pipe(p2);                              // ★ pipe2 : p2[0]=lecture p2[1]=écriture
    write(p1[1], "42", 2);                 // ★ écrire dans p1
    close(p1[1]);                          // ★ EOF pour le lecteur de p1
    char buf1[8];
    ssize_t n1 = read(p1[0], buf1, sizeof(buf1) - 1); // ★ lire depuis p1
    buf1[n1] = '\0';
    close(p1[0]);
    printf("Pipe1: %s\n", buf1);
    int val = atoi(buf1) * 2;             // ★ transformer : ×2
    char buf2[8];
    snprintf(buf2, sizeof(buf2), "%d", val);
    write(p2[1], buf2, strlen(buf2));      // ★ écrire résultat dans p2
    close(p2[1]);
    char out[8];
    ssize_t n2 = read(p2[0], out, sizeof(out) - 1);
    out[n2] = '\0';
    close(p2[0]);
    printf("Pipe2: %s\n", out);
    return 0;
}

